package com.example.sso.controller;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.List;

@Controller
public class LogoutController {

    @Value("${sso.logout.default-redirect:/login?logout}")
    private String defaultRedirectUrl;

    @Value("${sso.logout.allowed-redirect-domains:}")
    private List<String> allowedRedirectDomains;

    @Value("${sso.logout.allowed-redirect-urls:}")
    private List<String> allowedRedirectUrls;

    @GetMapping("/logout")
    public void logout(HttpServletRequest request,
                       HttpServletResponse response,
                       @RequestParam(name = "next", required = false) String next) throws IOException {

        // Invalidate session
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        // Clear security context (if using Spring Security manually)
        // SecurityContextHolder.clearContext();

        // Validate and redirect
        String safeRedirectUrl = validateRedirectUrl(next);
        response.sendRedirect(safeRedirectUrl);
    }

    /**
     * Validates the redirect URL to prevent Open Redirect attacks.
     * Only allows:
     * - Relative URLs (starting with "/" and not "//")
     * - URLs whose domain is in the configured allowlist
     * - Exact URLs in the configured allowlist
     */
    private String validateRedirectUrl(String redirectUrl) {
        if (redirectUrl == null || redirectUrl.isBlank()) {
            return defaultRedirectUrl;
        }

        // Reject protocol-relative URLs (e.g., "//evil.com")
        if (redirectUrl.startsWith("//")) {
            return defaultRedirectUrl;
        }

        // Allow relative paths (e.g., "/dashboard")
        if (redirectUrl.startsWith("/") && !redirectUrl.startsWith("//")) {
            // Additional check: reject URLs with backslashes or encoded characters that could bypass validation
            if (redirectUrl.contains("\\") || redirectUrl.contains("%0") || redirectUrl.contains("%1")) {
                return defaultRedirectUrl;
            }
            return redirectUrl;
        }

        // Check exact URL allowlist
        if (allowedRedirectUrls != null && allowedRedirectUrls.contains(redirectUrl)) {
            return redirectUrl;
        }

        // Check domain allowlist for absolute URLs
        if (allowedRedirectDomains != null && !allowedRedirectDomains.isEmpty()) {
            try {
                URI uri = new URI(redirectUrl);
                String scheme = uri.getScheme();
                String host = uri.getHost();

                // Only allow http and https schemes
                if (scheme != null && (scheme.equalsIgnoreCase("http") || scheme.equalsIgnoreCase("https"))
                        && host != null) {
                    for (String allowedDomain : allowedRedirectDomains) {
                        if (host.equals(allowedDomain) || host.endsWith("." + allowedDomain)) {
                            return redirectUrl;
                        }
                    }
                }
            } catch (URISyntaxException e) {
                // Invalid URI, fall through to default
            }
        }

        // If nothing matched, return the safe default
        return defaultRedirectUrl;
    }
}